import{_ as e,o as r,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"164. Hours Of Work","description":"","frontmatter":{"title":"164. Hours Of Work","eba":"Mental Health Services 2024-2028","topics":["leave","hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/164-hours-of-work.md","filePath":"ebas/mental-health/support-services/preliminary/164-hours-of-work.md"}'),a={name:"ebas/mental-health/support-services/preliminary/164-hours-of-work.md"};function n(i,o,h,u,p,f){return r(),t("div",null,[...o[0]||(o[0]=[s('<h1 id="_164-hours-of-work" tabindex="-1">164. Hours Of Work <a class="header-anchor" href="#_164-hours-of-work" aria-label="Permalink to &quot;164. Hours Of Work&quot;">​</a></h1><p><strong>164.1</strong> The ordinary hours of work for a full-time Employee shall be 38 hours, or an average of 38 hours, per week.</p><p><strong>164.2</strong> For the purposes of clause 164.1, the ordinary hours an Employee works in a week are taken to include any hours of authorised leave, or absence, whether paid or unpaid, that the Employee takes in a week.</p><p><strong>164.3</strong> The working week shall commence at midnight on a Sunday.</p><p><strong>164.4</strong> Notwithstanding any authorised meal breaks or rest breaks, the work of each day/shift shall be continuous.</p><p><strong>164.5</strong> The hours for an ordinary weeks work shall be 38 or be an average of 38 per week in a fortnight, or in a four-week period or by mutual agreement, in a five-week period in the case of an Employee working ten-hour shifts and shall be worked either:</p><p><strong>(a)</strong> in 5 days in shifts of not more than 8 hours each; or</p><p><strong>(b)</strong> in a fortnight of 76 hours in 10 shifts of not more than 8 hours each; or</p><p><strong>(c)</strong> in a four-week period of 152 hours in 19 shifts of not more than 8 hours each; or</p><p><strong>(d)</strong> by mutual agreement:</p><p><strong>(i)</strong> in weeks of four days in shifts of not more than 10 hours each; or</p><p><strong>(ii)</strong> in a fortnight of 76 hours in eight shifts of not more than ten hours each.</p><p><strong>164.6</strong> Any Employee required to work more than six consecutive periods of duty without 24 hours off duty shall be paid for the seventh and any further consecutive period of ordinary duty worked at the rate of triple time until they have been given 24 hours off duty.</p>',13)])])}const c=e(a,[["render",n]]);export{d as __pageData,c as default};
